    {
        "role": "paragraph",
        "segment": "The provided context does not contain any information about the Standish Group's CHAOS Report findings regarding software project success rates in 2020.",
        "citations": [
            {
                "type": "source_text",
                "content": "In 1994, the Standish Group surveyed over 350 companies about their over 8000 software projects to find out how well they were faring.The results are sobering.Thirty-one percent of the software projects were canceled before they were completed. Moreover, in large companies, only 9% of the projects were delivered on time and within budget; 16% met those criteria in small companies (Standish 1994). Similar results have been reported since then; the bottom line is that developers have trouble delivering the right system on time and within budget.",
                "img_id": null
            }
        ],
        "type": null
    }
]

